// === グローバル印刷CSS ===
const PRINT_STYLE = `
@media print {
  body, html { margin: 0 !important; padding: 0 !important; height: auto !important; overflow: visible !important; background: white !important; }
  #root { height: auto !important; overflow: visible !important; }
  .no-print, .sidebar, nav, header, [data-sidebar], [data-nav] { display: none !important; }
  .print-content { display: block !important; width: 100% !important; height: auto !important; overflow: visible !important; }
  @page { size: A4 portrait; margin: 0; }
}`;

function applyPrintAndOpen(title) {
  const prev = document.title;
  document.title = title;
  const style = document.createElement('style');
  style.id = 'print-override';
  style.textContent = PRINT_STYLE;
  document.head.appendChild(style);
  window.print();
  setTimeout(() => {
    document.title = prev;
    const el = document.getElementById('print-override');
    if (el) el.remove();
  }, 1500);
}

// === html2pdf共通ヘルパー ===
const loadHtml2Pdf = () => new Promise((resolve, reject) => {
  if (window.html2pdf) { resolve(window.html2pdf); return; }
  const s = document.createElement('script');
  s.src = 'https://cdnjs.cloudflare.com/ajax/libs/html2pdf.js/0.10.1/html2pdf.bundle.min.js';
  s.onload = () => resolve(window.html2pdf);
  s.onerror = reject;
  document.head.appendChild(s);
});

const downloadPdf = async (element, filename) => {
  const h2p = await loadHtml2Pdf();
  await h2p().set({
    margin: 0,
    filename,
    image: { type: 'jpeg', quality: 0.98 },
    html2canvas: { scale: 2, useCORS: true },
    jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
  }).from(element).save();
};

// === 1行に収まるよう自動縮小するテキスト（折り返さず scale で fit させる） ===
const AutoFitLine = ({ children, style }) => {
  const containerRef = React.useRef(null);
  const textRef = React.useRef(null);
  const [scale, setScale] = React.useState(1);
  React.useEffect(() => {
    const measure = () => {
      if (!textRef.current || !containerRef.current) return;
      const tw = textRef.current.scrollWidth;
      const cw = containerRef.current.clientWidth;
      setScale((tw > cw && cw > 0) ? cw / tw : 1);
    };
    measure();
    let ro;
    if (typeof ResizeObserver !== 'undefined' && containerRef.current) {
      ro = new ResizeObserver(measure);
      ro.observe(containerRef.current);
    }
    return () => { if (ro) ro.disconnect(); };
  }, [children]);
  return (
    <span ref={containerRef} style={{...style, overflow:'hidden', display:'inline-block', verticalAlign:'bottom'}}>
      <span ref={textRef} style={{whiteSpace:'nowrap', display:'inline-block', transformOrigin:'left center', transform: scale < 1 ? `scale(${scale})` : 'none'}}>
        {children}
      </span>
    </span>
  );
};

// === 利用者プルダウン: かな順ソート + 行（ア/カ/サ...）optgroup ===
// 並び順は kana 優先、なければ name を fallback。空文字 / 記号は「その他」へ。
const _KANA_ROWS = [
  ['ア行', /^[ぁ-おァ-オ]/],
  ['カ行', /^[が-ごカ-ゴか-こ]/],
  ['サ行', /^[ざ-ぞサ-ゾさ-そ]/],
  ['タ行', /^[だ-どタ-ドた-と]/],
  ['ナ行', /^[な-のナ-ノ]/],
  ['ハ行', /^[ば-ぽハ-ポは-ほ]/],
  ['マ行', /^[ま-もマ-モ]/],
  ['ヤ行', /^[ゃ-よャ-ヨ]/],
  ['ラ行', /^[ら-ろラ-ロ]/],
  ['ワ行', /^[わ-んワ-ン]/],
];
const _sortKey = (p) => (p.kana || p.name || '').trim();
const sortPatientsByKana = (list) => [...list].sort((a, b) => _sortKey(a).localeCompare(_sortKey(b), 'ja'));
const groupPatientsByKanaRow = (list) => {
  const sorted = sortPatientsByKana(list);
  const groups = _KANA_ROWS.map(([label, re]) => ({ label, items: sorted.filter(p => re.test(_sortKey(p))) }));
  const used = new Set();
  groups.forEach(g => g.items.forEach(p => used.add(p.id)));
  const other = sorted.filter(p => !used.has(p.id));
  if (other.length > 0) groups.push({ label: 'その他', items: other });
  return groups.filter(g => g.items.length > 0);
};

// === 印刷プレビューモーダル ===
function PrintPreviewModal({ children, title, onClose, onPrint }) {
  React.useEffect(() => {
    const handler = (e) => { if(e.key === 'Escape') onClose(); };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [onClose]);
  return (
    <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.7)',zIndex:9000,display:'flex',flexDirection:'column'}}>
      <div style={{background:'#2d3748',padding:'8px 16px',display:'flex',alignItems:'center',gap:12,flexShrink:0}}>
        <span style={{color:'white',fontWeight:'bold',fontSize:14}}>📄 印刷プレビュー — {title}</span>
        <div style={{marginLeft:'auto',display:'flex',gap:8}}>
          <button onClick={onPrint} style={{background:'#2563eb',color:'white',border:'none',borderRadius:8,padding:'6px 16px',fontWeight:'bold',fontSize:13,cursor:'pointer',display:'flex',alignItems:'center',gap:6}}>
            🖨️ 印刷 / PDF保存
          </button>
          <button onClick={onClose} style={{background:'#4a5568',color:'white',border:'none',borderRadius:8,padding:'6px 12px',fontWeight:'bold',fontSize:13,cursor:'pointer'}}>✕ 閉じる</button>
        </div>
      </div>
      <div style={{flex:1,overflow:'auto',background:'#525659',padding:24,display:'flex',flexDirection:'column',alignItems:'center',gap:16}}>
        <style>{`@media print { body,html,#root { height:auto!important;overflow:visible!important;background:white!important; } .no-print{display:none!important;} }`}</style>
        <div style={{width:794,background:'white',boxShadow:'0 4px 24px rgba(0,0,0,0.5)',transformOrigin:'top center',
          transform:`scale(${Math.min(1,(window.innerWidth-80)/794)})`,
          marginBottom:`${(Math.min(1,(window.innerWidth-80)/794)-1)*1123}px`}}>
          {children}
        </div>
      </div>
    </div>
  );
}

