// === 年齢計算ヘルパー ===
const calcAge = (birthDate) => { if(!birthDate) return null; const b=new Date(birthDate); const n=new Date(); let age=n.getFullYear()-b.getFullYear(); if(n.getMonth()<b.getMonth()||(n.getMonth()===b.getMonth()&&n.getDate()<b.getDate())) age--; return age; };

// 全角→半角変換（ID/PW 入力用）
const toHalfWidth = (s) => (s||'')
  .replace(/[！-～]/g, c => String.fromCharCode(c.charCodeAt(0) - 0xFEE0))
  .replace(/　/g, ' ')
  .replace(/[ー－]/g, '-');

// 招待コード関連 (利用者ID 6桁 + チェックデジット 1桁 = 7桁)
// patientId (任意の正数) を 6桁ゼロパディングし、各桁の合計 mod 10 のチェックデジットを付与
const calcCheckDigit = (sixDigitStr) => {
  const sum = sixDigitStr.split('').reduce((s,c) => s + (parseInt(c,10)||0), 0);
  return String(sum % 10);
};
// 利用者 ID から 7桁招待コードを生成 (内部用)
const generateInviteCode = (patientId) => {
  const six = String(patientId).padStart(6,'0').slice(-6);
  return six + calcCheckDigit(six);
};
// 7桁招待コードを検証 → 不正なら null、正しければ最初の6桁 (= 利用者ID と照合する値) を返す
const verifyInviteCode = (code7) => {
  const s = (code7||'').replace(/[^0-9]/g,'');
  if (s.length !== 7) return null;
  const six = s.slice(0,6);
  const expectedCD = calcCheckDigit(six);
  if (s[6] !== expectedCD) return null;
  return six;
};

// 日付文字列 ("4月15日" 等) を YYYY-MM に正規化。年が無いものは currentYear で補完
const normalizeRecordMonth = (dateStr, currentYear) => {
  if (!dateStr) return null;
  const isoM = dateStr.match(/^(\d{4})-(\d{2})/);
  if (isoM) return `${isoM[1]}-${isoM[2]}`;
  const m = dateStr.match(/(\d+)月/);
  if (m) {
    const yr = currentYear || new Date().getFullYear();
    return `${yr}-${String(m[1]).padStart(2,'0')}`;
  }
  return null;
};

// その日付に有効だった予定運動メニュー項目を返す (時系列バージョニング)
const getExerciseItemsForDate = (systemSettings, dateStr, currentYear) => {
  const current = systemSettings?.exerciseItems || appSettings.exerciseItems;
  const history = systemSettings?.exerciseItemsHistory || [];
  if (!history.length) return current;
  const ymd = normalizeRecordMonth(dateStr, currentYear);
  if (!ymd) return current;
  // 履歴の中で「effectiveTo 以下に ymd が収まる最も古いもの」を選択。
  // 全 effectiveTo より新しい場合は現行版。
  const sorted = [...history].sort((a,b)=>(a.effectiveTo||'').localeCompare(b.effectiveTo||''));
  for (const h of sorted) {
    if (!h.effectiveTo || ymd <= h.effectiveTo) return h.items;
  }
  return current;
};

