function AbsenceFaxView({ appData, onSave, dirtyRef, onShowPrintPreview }) {
  const markDirty = React.useCallback(()=>{ if(dirtyRef) dirtyRef.current=true; },[dirtyRef]);
  const markClean = React.useCallback(()=>{ if(dirtyRef) dirtyRef.current=false; },[dirtyRef]);
  const [currentMonth, setCurrentMonth] = React.useState(() => { const d=new Date(); return new Date(d.getFullYear(),d.getMonth(),1); });
  const [selectedEntry, setSelectedEntry] = React.useState(null);
  // 保存済みの faxDataStore を初期値として読み込む（再表示時に編集状態が消えないように）
  const [faxData, setFaxData] = React.useState(() => appData.faxDataStore || {});
  const [isPrint, setIsPrint] = React.useState(false);
  const [showFaxHist, setShowFaxHist] = React.useState(false);
  const absHistory = (appData.faxHistory||[]).filter(h => h.type === 'absence');
  const deleteAbsHist = (id) => onSave({...appData, faxHistory: (appData.faxHistory||[]).filter(h => h.id !== id)});
  // 担当者プルダウン: 各種設定の従業員から選択。デフォルトは管理者
  const staffList = (appData.diarySettings?.staff || []).filter(s => s.name && s.name.trim());
  const defaultManagerName = (staffList.find(s => s.role === '管理者')?.name) || staffList[0]?.name || (appData.systemSettings?.facilityInfo?.manager) || '';
  const [selectedManager, setSelectedManager] = React.useState(defaultManagerName);

  const facility = appData.systemSettings?.facilityInfo || {};
  const patients = appData.patients || [];
  const tickets = appData.ticketRecords || [];

  const maskName = (name) => {
    if (!name) return '●●';
    // 各単語（姓・名）を個別にマスキング
    // 2文字: 1文字目表示、2文字目● (山田→山●、タカ→タ●)
    // 3文字: 1文字目表示、2文字目●、3文字目表示 (ハルエ→ハ●エ)
    // 1文字: そのまま
    const maskWord = (word) => {
      if (!word) return '';
      if (word.length === 1) return word;
      if (word.length === 2) return word[0] + '●';
      if (word.length === 3) return word[0] + '●' + word[2];
      // 4文字以上: 1文字目と最後表示、中間を●
      return word[0] + '●'.repeat(word.length - 2) + word[word.length - 1];
    };
    const parts = name.trim().split(/\s+/);
    return parts.map(maskWord).join(' ');
  };

  const cY = currentMonth.getFullYear(), cM = currentMonth.getMonth()+1;
  const daysInMonth = new Date(cY, cM, 0).getDate();
  const firstDow = new Date(cY, cM-1, 1).getDay();
  const dayNames = ['日','月','火','水','木','金','土'];

  // 当月の欠席者を日付別に集計
  const absencesByDate = {};
  tickets.forEach(r => {
    if (r.status !== '欠席') return;
    const m = r.date?.match(/(\d+)月(\d+)日/);
    if (!m) return;
    const rm = parseInt(m[1]), rd = parseInt(m[2]);
    if (rm !== cM) return;
    const dateStr = `${cY}-${String(cM).padStart(2,'0')}-${String(rd).padStart(2,'0')}`;
    if (!absencesByDate[dateStr]) absencesByDate[dateStr] = [];
    const pat = patients.find(p => p.id === r.patientId);
    if (pat) absencesByDate[dateStr].push({ patient: pat, tokki: r.tokki || '' });
  });

  const getKey = (date, patId) => `${date}_${patId}`;
  const getFax = (date, patId) => faxData[getKey(date, patId)] || { checkboxes: { kyuukyuu: false, kakunin: false, orikaesu: false }, reporter: '', status: 'none' };

  const openFax = (date, pat, tokki) => {
    setSelectedEntry({ date, patient: pat, tokki });
  };

  const closeFax = () => { setSelectedEntry(null); setIsPrint(false); };

  const updateFax = (key, updates) => {
    setFaxData(prev => ({ ...prev, [key]: { ...getFax(...key.split('_')), ...updates } }));
  };

  // 今日日付（和暦）
  const toWareki = (dateStr) => {
    const d = new Date(dateStr);
    const y = d.getFullYear();
    // 令和
    if (y >= 2019) return `令和${y-2018}年${d.getMonth()+1}月${d.getDate()}日`;
    return `${y}年${d.getMonth()+1}月${d.getDate()}日`;
  };

  const handlePrint = () => {
    const doAfterPrint = () => { document.title='DayCare v2';setIsPrint(false);if(selectedEntry){const key=getKey(selectedEntry.date,selectedEntry.patient.id);updateFax(key,{status:'printed'});}};
    if(onShowPrintPreview){setIsPrint(true);setTimeout(()=>{onShowPrintPreview(`休み連絡_${selectedEntry?.patient?.name||''}`, 'A4 portrait', 'print-content-fax');doAfterPrint();},100);}
    else{setIsPrint(true);document.title=`休み連絡_${selectedEntry?.patient?.name||''}`;setTimeout(()=>{window.print();setTimeout(doAfterPrint,500);},100);}
  };
  const handleSavePdf = () => {
    const doAfterPdf=()=>{document.title='DayCare v2';setIsPrint(false);if(selectedEntry){const key=getKey(selectedEntry.date,selectedEntry.patient.id);const cur=getFax(selectedEntry.date,selectedEntry.patient.id);updateFax(key,{status:cur.status==='printed'?'both':'pdf'});}};
    if(onShowPrintPreview){setIsPrint(true);setTimeout(()=>{onShowPrintPreview(`休み連絡_${selectedEntry?.patient?.name||''}`, 'A4 portrait', 'print-content-fax');doAfterPdf();},100);}
    else{setIsPrint(true);document.title=`休み連絡_${selectedEntry?.patient?.name||''}`;setTimeout(()=>{window.print();setTimeout(doAfterPdf,500);},100);}
  };

  // 送付状画面
  if (selectedEntry) {
    const { date, patient, tokki } = selectedEntry;
    const key = getKey(date, patient.id);
    const fax = getFax(date, patient.id);
    const maskedName = maskName(patient.name);
    const today = toWareki(new Date().toISOString().split('T')[0]);
    const absDate = toWareki(date);
    const checks = fax.checkboxes;
    // tokki から振替情報と理由を分離
    // 例: "4月9日AMへ振替（私用）" → reason:"私用", furikaeNote:"4月9日AM振替"
    const parseFurikaeTokki = (t) => {
      if (!t || !t.includes('振替')) return { isFurikae: false, reason: t || '', furikaeNote: '' };
      // "○月○日AMへ振替（理由）" のパターン
      const noteM = t.match(/^(.+?へ振替)/);
      const reasonM = t.match(/（(.+?)）/);
      const furikaeNote = noteM ? noteM[1].replace('へ振替','振替') : '';
      const reason = reasonM ? reasonM[1] : '';
      return { isFurikae: true, reason, furikaeNote };
    };

    const rawTokki = (() => {
      if (tokki) return tokki;
      const rec = tickets.find(r => r.patientId === patient.id && r.date === `${parseInt(date.split('-')[1])}月${parseInt(date.split('-')[2])}日` && r.status === '欠席');
      return rec?.tokki || '';
    })();
    const parsed = parseFurikaeTokki(rawTokki);

    const defaultReason = fax.reason !== undefined ? fax.reason : parsed.reason || rawTokki;
    const defaultMemo = fax.memo !== undefined ? fax.memo : (parsed.isFurikae && parsed.furikaeNote ? parsed.furikaeNote : '');

    return (
      <div style={{height:'100%',display:'flex',flexDirection:'column',background:'#f0f4f9'}}>
        {/* 操作バー（スクロール時も上部に固定） */}
        <div className="fax-no-print" style={{position:'sticky',top:0,zIndex:30,flexShrink:0,background:'#1e293b',color:'white',padding:'10px 20px',display:'flex',alignItems:'center',gap:10,flexWrap:'wrap'}}>
          <button type="button" onClick={closeFax} style={{background:'rgba(255,255,255,0.1)',border:'1px solid rgba(255,255,255,0.2)',color:'white',borderRadius:8,padding:'6px 14px',fontWeight:'bold',fontSize:13,cursor:'pointer',display:'flex',alignItems:'center',gap:6}}>
            ← カレンダーに戻る
          </button>
          <span style={{fontSize:13,fontWeight:'bold',color:'#94a3b8'}}>{absDate}　{maskedName} 様</span>
          <div style={{marginLeft:'auto',display:'flex',gap:8,flexWrap:'wrap'}}>
            <button type="button" onClick={()=>{
              // プレビューモーダルへ + 送付履歴を自動記録
              const el = document.getElementById('print-content-fax');
              if(!el) return;
              setIsPrint(true);
              // 送付履歴を自動記録（利用者名 / ケアマネ名 / 送付日）
              const newEntry = {
                id: `fax_${Date.now()}_${Math.random().toString(36).slice(-4)}`,
                type: 'absence',
                timestamp: new Date().toISOString(),
                subject: `休み連絡 (${absDate})`,
                patientName: selectedEntry?.patient?.name || '',
                recipientName: selectedEntry?.patient?.cmName || '',
                recipientFax: selectedEntry?.patient?.cmFax || '',
                recipientOffice: selectedEntry?.patient?.cmOffice || '',
                note: '自動記録',
              };
              onSave({...appData, faxHistory: [newEntry, ...(appData.faxHistory||[])]});
              setTimeout(()=>{
                onShowPrintPreview(`休み連絡_${selectedEntry?.patient?.name||''}`, 'A4 portrait', 'print-content-fax');
                setIsPrint(false);
              },100);
            }} style={{background:'#0f766e',border:'none',color:'white',borderRadius:8,padding:'6px 14px',fontWeight:'bold',fontSize:12,cursor:'pointer',display:'flex',alignItems:'center',gap:5}}>
              📋 プレビュー
            </button>
            <button type="button" onClick={()=>{
              markClean();
              // faxData で編集された理由(reason)を、対応する ticketRecord.tokki にも反映
              // → カレンダーや他画面が参照する欠席理由が同期される
              let newTickets = appData.ticketRecords || [];
              Object.entries(faxData).forEach(([k, fx]) => {
                if (!fx || fx.reason === undefined) return; // 編集が無い key はスキップ
                const [dateIso, patIdStr] = k.split('_');
                const pid = parseInt(patIdStr, 10);
                if (!dateIso || !pid) return;
                const parts = dateIso.split('-');
                if (parts.length < 3) return;
                const dateStr = `${parseInt(parts[1])}月${parseInt(parts[2])}日`;
                newTickets = newTickets.map(r => {
                  if (r.patientId !== pid || r.date !== dateStr || r.status !== '欠席') return r;
                  // 元 tokki が「○月○日AMへ振替（理由）」の形なら、振替ノートを保持して理由だけ差し替える
                  const m = (r.tokki || '').match(/^(.+?へ振替)/);
                  const newTokki = m ? `${m[1]}（${fx.reason}）` : fx.reason;
                  return { ...r, tokki: newTokki };
                });
              });
              onSave({...appData, faxDataStore: {...(appData.faxDataStore||{}), ...faxData}, ticketRecords: newTickets});
            }} style={{background:'#2563eb',border:'none',color:'white',borderRadius:8,padding:'6px 14px',fontWeight:'bold',fontSize:12,cursor:'pointer',display:'flex',alignItems:'center',gap:5}}>
              <Save size={13}/> 保存
            </button>
          </div>
        </div>

        {/* A4送付状 — A4ポートレート 210x297mm 内に余白付きで収める */}
        <style>{`
          @page { size: A4 portrait; margin: 0; }
          @media print {
            body, html { margin:0!important; padding:0!important; overflow:hidden!important; width:210mm!important; height:297mm!important; }
            body { display:flex!important; justify-content:center!important; align-items:flex-start!important; }
            body>* { margin:0!important; padding:0!important; }
            #print-content-fax {
              width:190mm!important; height:280mm!important; max-height:280mm!important;
              margin:8mm auto!important;
              box-shadow:none!important;
              page-break-after:avoid!important; break-after:avoid!important;
              page-break-inside:avoid!important; break-inside:avoid!important;
              overflow:hidden!important;
            }
          }
        `}</style>
        <div style={{flex:1,overflow:'auto',display:'flex',justifyContent:'center',alignItems:'flex-start',padding:'20px',background:'#f0f4f9'}}>
          <div id="print-content-fax" style={{width:'190mm',height:'280mm',maxHeight:'280mm',overflow:'hidden',background:'white',boxShadow:'0 4px 24px rgba(0,0,0,0.12)',padding:'12mm 14mm',boxSizing:'border-box',fontFamily:'serif',position:'relative',display:'flex',flexDirection:'column',margin:'0 auto'}}>

            {/* タイトル */}
            <div style={{textAlign:'center',fontSize:28,fontWeight:'bold',border:'3px solid black',padding:'10px 0',marginBottom:28,letterSpacing:6}}>送付状</div>

            {/* 上部2列 */}
            <div style={{display:'flex',gap:0,marginBottom:20}}>
              {/* 左：送付先情報 */}
              <div style={{flex:1,paddingRight:24}}>
                <div style={{display:'grid',gridTemplateColumns:'90px 1fr',gap:'8px 10px',marginBottom:16,fontSize:16}}>
                  <span style={{fontWeight:'bold'}}>送付日：</span>
                  <span>{today}</span>
                  <span style={{fontWeight:'bold'}}>送付枚数：</span>
                  <span>1 枚（表紙含）</span>
                  <span style={{fontWeight:'bold'}}>送付先：</span>
                  <span></span>
                </div>
                <div style={{marginLeft:90,marginBottom:10,fontSize:17,borderBottom:'1px solid black',paddingBottom:5,display:'flex',justifyContent:'space-between',alignItems:'flex-end',gap:8}}>
                  <AutoFitLine style={{flex:1,minWidth:0,fontSize:17}}>{patient.cmOffice || '　'}</AutoFitLine>
                  <span style={{fontWeight:'bold',flexShrink:0,whiteSpace:'nowrap'}}>御中</span>
                </div>
                <div style={{marginLeft:90,marginBottom:10,fontSize:17,borderBottom:'1px solid black',paddingBottom:5,display:'flex',justifyContent:'space-between',alignItems:'flex-end',gap:8}}>
                  <AutoFitLine style={{flex:1,minWidth:0,fontSize:17}}>{patient.cmName || '　'}</AutoFitLine>
                  <span style={{fontWeight:'bold',flexShrink:0,whiteSpace:'nowrap'}}>様</span>
                </div>
                {patient.cmFax && (
                  <div style={{marginLeft:90,fontSize:14,color:'#475569',marginTop:6}}>
                    FAX：{patient.cmFax}
                  </div>
                )}
              </div>

              {/* 右：発信元（フォント拡大 + 2行に折り返す場合は自動縮小） */}
              <div style={{width:280,border:'2px solid black',padding:'12px 16px',fontSize:16,lineHeight:1.7}}>
                <AutoFitLine style={{fontWeight:'bold',fontSize:19,marginBottom:6,display:'block',width:'100%'}}>{facility.name || 'ひかりデイサービス扇橋店'}</AutoFitLine>
                <AutoFitLine style={{display:'block',width:'100%'}}>〒{facility.zip||'135-0011'}</AutoFitLine>
                <AutoFitLine style={{display:'block',width:'100%'}}>{facility.address||'東京都江東区扇橋1-4-9メイゾン白子'}</AutoFitLine>
                <AutoFitLine style={{display:'block',width:'100%'}}>TEL：{facility.phone||'03-6458-7415'}</AutoFitLine>
                <AutoFitLine style={{display:'block',width:'100%'}}>FAX：{facility.fax||'03-6458-7416'}</AutoFitLine>
                <div style={{display:'flex',alignItems:'center',gap:4,width:'100%'}}>
                  <span style={{whiteSpace:'nowrap'}}>担当：　</span>
                  <select value={selectedManager} onChange={e=>setSelectedManager(e.target.value)}
                    style={{flex:1,fontSize:16,fontFamily:'inherit',border:'none',outline:'none',background:'transparent',padding:'0 2px',cursor:'pointer',appearance:'none',WebkitAppearance:'none',MozAppearance:'none',color:'inherit'}}>
                    {staffList.length === 0 && <option value="">（従業員未登録）</option>}
                    {staffList.map((s, i) => (
                      <option key={s.id || i} value={s.name}>{s.name}{s.role ? `（${s.role}）` : ''}</option>
                    ))}
                  </select>
                </div>
              </div>
            </div>

            {/* 件名 */}
            <div style={{display:'flex',alignItems:'center',gap:16,marginBottom:20,borderBottom:'3px double black',paddingBottom:12}}>
              <span style={{fontSize:16,fontWeight:'bold'}}>件名：</span>
              <span style={{fontSize:20,fontWeight:'bold',letterSpacing:2}}>お休み連絡</span>
            </div>

            {/* チェックボックス（クリックで切り替え） */}
            <div style={{display:'flex',gap:28,marginBottom:12,fontSize:13,fontWeight:'bold',alignItems:'center'}}>
              {[['kyuukyuu','至急！'],['kakunin','ご確認ください'],['orikaesu','折り返しご連絡ください']].map(([k,label])=>(
                <button key={k} type="button"
                  onClick={()=>updateFax(key,{checkboxes:{...checks,[k]:!checks[k]}})}
                  style={{display:'flex',alignItems:'center',gap:6,cursor:'pointer',background:'none',border:'none',padding:0,fontWeight:'bold',fontSize:13}}>
                  <span style={{
                    display:'inline-flex',alignItems:'center',justifyContent:'center',
                    width:16,height:16,border:`2px solid ${checks[k]?'#1e293b':'#94a3b8'}`,
                    borderRadius:3,background:checks[k]?'#1e293b':'white',color:'white',
                    fontSize:11,fontWeight:'bold',flexShrink:0
                  }}>{checks[k]?'✓':''}</span>
                  <span style={{color:checks[k]?'#1e293b':'#94a3b8'}}>{label}</span>
                </button>
              ))}
            </div>

            <div style={{fontSize:11,color:'#334155',marginBottom:16}}>・送付されていないページがありましたら、至急ご連絡ください。</div>

            {/* 本文枠 */}
            <div style={{border:'2px solid black',padding:'24px 28px',lineHeight:2.2,fontSize:13,flex:1,display:'flex',flexDirection:'column'}}>

              {/* 利用者名 */}
              <div style={{fontSize:19,fontWeight:'bold',marginBottom:20,borderBottom:'1px solid #e2e8f0',paddingBottom:14,display:'flex',alignItems:'center',gap:8}}>
                <span style={{color:'#475569',fontWeight:'bold',whiteSpace:'nowrap'}}>利用者名：</span>
                <span style={{borderBottom:'2px solid #1e293b',paddingBottom:2,letterSpacing:2}}>{maskedName}</span>
                <span>様</span>
              </div>

              {/* 欠席情報 */}
              <div style={{marginBottom:20}}>
                <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:14}}>
                  <span style={{fontWeight:'bold',whiteSpace:'nowrap',minWidth:80,fontSize:17}}>欠席日：</span>
                  <span style={{fontSize:17,fontWeight:'bold',letterSpacing:1}}>{absDate}</span>
                </div>
                <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:14}}>
                  <span style={{fontWeight:'bold',whiteSpace:'nowrap',minWidth:80,fontSize:17}}>理由：</span>
                  {isPrint ? (
                    <span style={{flex:1,borderBottom:'1px solid #334155',minHeight:26,fontSize:16}}>{fax.reason ?? defaultReason}</span>
                  ) : (
                    <input type="text" value={fax.reason ?? defaultReason} onChange={e=>updateFax(key,{reason:e.target.value})}
                      style={{flex:1,border:'none',borderBottom:'1px solid #334155',outline:'none',fontSize:16,background:'transparent',padding:'2px 0'}}/>
                  )}
                </div>
                <div style={{display:'flex',alignItems:'center',gap:8}}>
                  <span style={{fontWeight:'bold',whiteSpace:'nowrap',minWidth:80,fontSize:17}}>連絡者：</span>
                  {isPrint ? (
                    <span style={{flex:1,borderBottom:'1px solid #334155',minHeight:26,fontSize:16}}>{fax.reporter||''}</span>
                  ) : (
                    <input type="text" value={fax.reporter||''} onChange={e=>updateFax(key,{reporter:e.target.value})}
                      placeholder="例：ご本人、ご家族（氏名）"
                      style={{flex:1,border:'none',borderBottom:'1px solid #334155',outline:'none',fontSize:16,background:'transparent',padding:'2px 0'}}/>
                  )}
                </div>
              </div>

              {/* 連絡事項 */}
              <div style={{marginBottom:0,flex:1,display:'flex',flexDirection:'column'}}>
                <div style={{fontWeight:'bold',fontSize:15,marginBottom:8,display:'flex',alignItems:'center',justifyContent:'space-between'}}>
                  <span>連絡事項</span>
                </div>
                {isPrint ? (
                  <div style={{flex:1,border:'1px solid #e2e8f0',borderRadius:4,padding:'8px 12px',fontSize:16,whiteSpace:'pre-wrap',lineHeight:1.8}}>
                    {fax.memo ?? defaultMemo}
                  </div>
                ) : (
                  <textarea
                    value={fax.memo ?? defaultMemo}
                    onChange={e=>updateFax(key,{memo:e.target.value})}
                    placeholder="連絡事項を自由に入力してください"
                    style={{width:'100%',flex:1,border:'1px solid #e2e8f0',borderRadius:4,padding:'8px 12px',fontSize:16,outline:'none',resize:'none',fontFamily:'serif',lineHeight:1.8,boxSizing:'border-box'}}
                  />
                )}
              </div>

              <div style={{fontSize:13,marginTop:8}}>今後ともよろしくお願いいたします。</div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // カレンダー画面
  const weeks = [];
  let cells = Array(firstDow).fill(null);
  for (let d=1; d<=daysInMonth; d++) {
    cells.push(d);
    if (cells.length===7) { weeks.push(cells); cells=[]; }
  }
  if (cells.length>0) { while(cells.length<7) cells.push(null); weeks.push(cells); }

  const statusColors = { none:'', edited:'#dbeafe', printed:'#dbeafe', pdf:'#dbeafe', both:'#dbeafe' };
  const statusLabels = { edited:'編集済', printed:'編集済', pdf:'編集済', both:'編集済' };
  // fax データが何らかの編集（理由・連絡者・備考・チェック）を含むかどうか
  const isFaxEdited = (fd) => {
    if (!fd) return false;
    if (typeof fd.reason === 'string' && fd.reason.trim() !== '') return true;
    if (typeof fd.reporter === 'string' && fd.reporter.trim() !== '') return true;
    if (typeof fd.memo === 'string' && fd.memo.trim() !== '') return true;
    const cb = fd.checkboxes || {};
    if (cb.kyuukyuu || cb.kakunin || cb.orikaesu) return true;
    return false;
  };

  return (
    <div style={{height:'100%',display:'flex',flexDirection:'column',background:'#f0f4f9'}}>
      {/* ヘッダー（スクロール時も上部に固定） */}
      <div style={{position:'sticky',top:0,zIndex:30,flexShrink:0,background:'linear-gradient(135deg,#1e293b,#334155)',color:'white',padding:'12px 20px',display:'flex',alignItems:'center',justifyContent:'space-between',boxShadow:'0 2px 8px rgba(0,0,0,0.2)'}}>
        <div style={{display:'flex',alignItems:'center',gap:10}}>
          <FileText size={20}/>
          <span style={{fontSize:17,fontWeight:'bold'}}>休み連絡</span>
        </div>
        <div style={{display:'flex',alignItems:'center',gap:8}}>
          <button type="button" onClick={()=>setCurrentMonth(new Date(cY,cM-2,1))} style={{background:'rgba(255,255,255,0.1)',border:'1px solid rgba(255,255,255,0.2)',color:'white',borderRadius:8,padding:'5px 12px',fontWeight:'bold',cursor:'pointer'}}>←</button>
          <span style={{fontSize:15,fontWeight:'bold',minWidth:100,textAlign:'center'}}>{cY}年{cM}月</span>
          <button type="button" onClick={()=>setCurrentMonth(new Date(cY,cM,1))} style={{background:'rgba(255,255,255,0.1)',border:'1px solid rgba(255,255,255,0.2)',color:'white',borderRadius:8,padding:'5px 12px',fontWeight:'bold',cursor:'pointer'}}>→</button>
        </div>
        <div style={{display:'flex',gap:10,fontSize:11,alignItems:'center'}}>
          <span style={{display:'flex',alignItems:'center',gap:4}}>
            <span style={{width:12,height:12,borderRadius:3,background:'#dbeafe',border:'1px solid #64748b',display:'inline-block'}}/>
            <span style={{color:'#cbd5e1'}}>編集済</span>
          </span>
          <button type="button" onClick={()=>setShowFaxHist(true)}
            style={{background:'#7c3aed',border:'none',color:'white',borderRadius:8,padding:'6px 14px',fontWeight:'bold',fontSize:12,cursor:'pointer',display:'flex',alignItems:'center',gap:5,marginLeft:8}}>
            📋 履歴
          </button>
        </div>
      </div>

      {/* カレンダー: 曜日ヘッダーを sticky にし、ヘッダーとの間に隙間を作らない */}
      <div style={{flex:1,overflow:'auto',padding:'0 20px 20px'}}>
        <div style={{background:'white',borderLeft:'1px solid #e2e8f0',borderRight:'1px solid #e2e8f0',borderBottom:'1px solid #e2e8f0',borderBottomLeftRadius:14,borderBottomRightRadius:14,boxShadow:'0 1px 6px rgba(0,0,0,0.08)'}}>
          {/* 曜日ヘッダー（スクロール時も上に固定） */}
          <div style={{position:'sticky',top:0,zIndex:25,display:'grid',gridTemplateColumns:'repeat(7,1fr)',background:'#334155',borderTop:'1px solid #e2e8f0'}}>
            {['日','月','火','水','木','金','土'].map((d,i)=>{
              const isClosed=(appData.systemSettings?.facilityInfo?.closedDays||[0]).includes(i);
              return (
                <div key={d} style={{padding:'10px 0',textAlign:'center',fontWeight:'bold',fontSize:13,color:isClosed?'#64748b':i===0?'#fca5a5':i===6?'#93c5fd':'white',position:'relative'}}>
                  {d}{isClosed&&<span style={{fontSize:9,display:'block',color:'#475569'}}>定休</span>}
                </div>
              );
            })}
          </div>
          {/* 日付セル */}
          {weeks.map((week,wi)=>(
            <div key={wi} style={{display:'grid',gridTemplateColumns:'repeat(7,1fr)',borderTop:'1px solid #f1f5f9'}}>
              {week.map((day,di)=>{
                if (!day) return <div key={di} style={{minHeight:90,background:'#f8fafc',borderRight:'1px solid #f1f5f9'}}/>;
                const dateStr = `${cY}-${String(cM).padStart(2,'0')}-${String(day).padStart(2,'0')}`;
                const absences = absencesByDate[dateStr] || [];
                const today = new Date(); today.setHours(0,0,0,0);
                const isToday = new Date(dateStr).getTime()===today.getTime();
                const isClosed = (appData.systemSettings?.facilityInfo?.closedDays||[0]).includes(di);
                return (
                  <div key={di} style={{minHeight:90,borderRight:'1px solid #f1f5f9',padding:'6px 6px 4px',background:isClosed?'#f1f5f9':isToday?'#fffbeb':'white',position:'relative'}}>
                    <div style={{fontSize:13,fontWeight:'bold',color:isClosed?'#cbd5e1':di===0?'#dc2626':di===6?'#2563eb':'#334155',marginBottom:4,display:'flex',alignItems:'center',gap:4}}>
                      {day}
                      {isToday&&!isClosed&&<span style={{fontSize:9,background:'#f59e0b',color:'white',borderRadius:4,padding:'1px 4px',fontWeight:'bold'}}>今日</span>}
                      {isClosed&&<span style={{fontSize:9,color:'#94a3b8'}}>定休</span>}
                    </div>
                    {absences.map(({patient:pat, tokki},ai)=>{
                      const k = getKey(dateStr, pat.id);
                      const fd = faxData[k];
                      // 印刷/PDF状態が無くても編集されていれば「編集済」を表示
                      const rawSt = fd?.status || 'none';
                      const st = (rawSt === 'none' && isFaxEdited(fd)) ? 'edited' : rawSt;
                      const maskedN = pat.name;  // カレンダーはマスキングなし
                      return (
                        <button key={ai} type="button" onClick={()=>{if(!isClosed) openFax(dateStr, pat, tokki);}}
                          style={{
                            width:'100%',marginBottom:3,padding:'3px 5px',borderRadius:6,border:'none',
                            background:st!=='none'?statusColors[st]:'#fef2f2',
                            color:'#1e293b',fontSize:11,fontWeight:'bold',cursor:'pointer',
                            textAlign:'left',display:'flex',alignItems:'center',gap:4
                          }}>
                          <span style={{flex:1,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{maskedN}</span>
                          {st!=='none'&&<span style={{fontSize:9,flexShrink:0,color:'#475569',background:'rgba(255,255,255,0.7)',padding:'1px 4px',borderRadius:3}}>{statusLabels[st]}</span>}
                        </button>
                      );
                    })}
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>
      {showFaxHist && <FaxHistoryListModal history={absHistory} typeLabel="休み連絡" onDelete={deleteAbsHist} onClose={()=>setShowFaxHist(false)}/>}
    </div>
  );
}


// === GeneralFaxView (各種連絡) ===
function GeneralFaxView({ appData, onSave, onShowPrintPreview }) {
  const [selectedPatientId, setSelectedPatientId] = React.useState(null);
  const [subject, setSubject] = React.useState('');
  const [memo, setMemo] = React.useState('');
  const [pageCount, setPageCount] = React.useState(1);
  const [checks, setChecks] = React.useState({ kyuukyuu: false, kakunin: false, orikaesu: false });
  const [showFaxHist, setShowFaxHist] = React.useState(false);
  // 御中の前 / 様の前 / 利用者名（利用者未選択時に手入力可能）
  const [recipientOffice, setRecipientOffice] = React.useState('');
  const [recipientName, setRecipientName] = React.useState('');
  const [customPatientName, setCustomPatientName] = React.useState('');
  // 担当者プルダウン: 各種設定の従業員から選択。デフォルトは管理者
  const staffList = (appData.diarySettings?.staff || []).filter(s => s.name && s.name.trim());
  const defaultManagerName = (staffList.find(s => s.role === '管理者')?.name) || staffList[0]?.name || (appData.systemSettings?.facilityInfo?.manager) || '';
  const [selectedManager, setSelectedManager] = React.useState(defaultManagerName);
  const genHistory = (appData.faxHistory||[]).filter(h => h.type === 'general');
  const deleteGenHist = (id) => onSave && onSave({...appData, faxHistory: (appData.faxHistory||[]).filter(h => h.id !== id)});

  const facility = appData.systemSettings?.facilityInfo || {};
  const patients = appData.patients || [];
  const patient = patients.find(p => p.id === selectedPatientId);

  // AbsenceFaxView と同じマスキング
  const maskName = (name) => {
    if (!name) return '●●';
    const maskWord = (word) => {
      if (!word) return '';
      if (word.length === 1) return word;
      if (word.length === 2) return word[0] + '●';
      if (word.length === 3) return word[0] + '●' + word[2];
      return word[0] + '●'.repeat(word.length - 2) + word[word.length - 1];
    };
    return name.trim().split(/\s+/).map(maskWord).join(' ');
  };

  const toWareki = (dateStr) => {
    const d = new Date(dateStr);
    const y = d.getFullYear();
    if (y >= 2019) return `令和${y-2018}年${d.getMonth()+1}月${d.getDate()}日`;
    return `${y}年${d.getMonth()+1}月${d.getDate()}日`;
  };

  const today = toWareki(new Date().toISOString().split('T')[0]);
  const maskedName = patient ? maskName(patient.name) : '';

  // 利用者選択を変えたとき、御中の前 / 様の前 / 利用者名の表示を自動補完
  React.useEffect(() => {
    if (patient) {
      setRecipientOffice(patient.cmOffice || '');
      setRecipientName(patient.cmName || '');
      setCustomPatientName(patient.name || '');
    } else {
      setRecipientOffice('');
      setRecipientName('');
      setCustomPatientName('');
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedPatientId]);

  const handlePreview = () => {
    const label = patient ? patient.name : (customPatientName || '汎用');
    if (onShowPrintPreview) onShowPrintPreview(`各種連絡_${label}`, 'A4 portrait', 'print-content-general-fax');
  };

  return (
    <div style={{height:'100%',display:'flex',flexDirection:'column',background:'#f0f4f9'}}>
      {/* 送付状内インライン入力の視覚ヒント（hover/focus でわずかな黄背景） */}
      <style>{`.fax-inline-input{transition:background 0.15s;}.fax-inline-input:hover{background:#fef9c3 !important;}.fax-inline-input:focus{background:#fef3c7 !important;}`}</style>
      {/* 操作バー: 利用者 / 送付件数 / マーク / プレビュー（スクロール時も上部に固定。他画面と同じサイズに揃え） */}
      <div className="fax-no-print" style={{position:'sticky',top:0,zIndex:30,flexShrink:0,background:'linear-gradient(135deg,#1e293b,#334155)',color:'white',padding:'12px 20px',display:'flex',alignItems:'center',gap:14,flexWrap:'wrap',boxShadow:'0 2px 8px rgba(0,0,0,0.2)'}}>
        <span style={{fontSize:17,fontWeight:'bold',whiteSpace:'nowrap',display:'flex',alignItems:'center',gap:6}}><FileText size={20}/>各種連絡</span>
        {/* 利用者 */}
        <label style={{display:'flex',alignItems:'center',gap:6,whiteSpace:'nowrap'}}>
          <span style={{fontSize:12,fontWeight:'bold',color:'#cbd5e1'}}>利用者:</span>
          <select value={selectedPatientId||''} onChange={e=>setSelectedPatientId(Number(e.target.value)||null)}
                  style={{padding:'5px 8px',border:'1px solid rgba(255,255,255,0.25)',borderRadius:6,fontSize:13,fontWeight:'bold',outline:'none',background:'rgba(255,255,255,0.1)',color:'white',minWidth:160,textAlign:'center',textAlignLast:'center'}}>
            <option value="" style={{color:'#1e293b'}}>— 利用者なし —</option>
            {groupPatientsByKanaRow(patients).map(g => (
              <optgroup key={g.label} label={g.label}>
                {g.items.map(p => <option key={p.id} value={p.id} style={{color:'#1e293b'}}>{p.name}</option>)}
              </optgroup>
            ))}
          </select>
        </label>
        {/* 送付件数 */}
        <label style={{display:'flex',alignItems:'center',gap:4,whiteSpace:'nowrap'}}>
          <span style={{fontSize:12,fontWeight:'bold',color:'#cbd5e1'}}>送付件数:</span>
          <button type="button" onClick={()=>setPageCount(c=>Math.max(1,c-1))}
                  style={{width:24,height:26,border:'1px solid rgba(255,255,255,0.25)',borderRadius:6,background:'rgba(255,255,255,0.1)',color:'white',fontWeight:'bold',fontSize:14,cursor:'pointer'}}>−</button>
          <input type="text" inputMode="numeric" value={pageCount}
                 onChange={e=>{const v=parseInt(e.target.value)||0; setPageCount(Math.max(1,Math.min(99,v||1)));}}
                 style={{width:46,padding:'4px 0',border:'1px solid rgba(255,255,255,0.25)',borderRadius:6,fontSize:13,fontWeight:'bold',outline:'none',background:'rgba(255,255,255,0.1)',color:'white',textAlign:'center',boxSizing:'border-box'}}/>
          <button type="button" onClick={()=>setPageCount(c=>Math.min(99,c+1))}
                  style={{width:24,height:26,border:'1px solid rgba(255,255,255,0.25)',borderRadius:6,background:'rgba(255,255,255,0.1)',color:'white',fontWeight:'bold',fontSize:14,cursor:'pointer'}}>+</button>
          <span style={{fontSize:12,fontWeight:'bold',color:'#cbd5e1'}}>枚</span>
        </label>
        {/* マーク */}
        <div style={{display:'flex',alignItems:'center',gap:10,flexWrap:'wrap'}}>
          <span style={{fontSize:12,fontWeight:'bold',color:'#cbd5e1'}}>マーク:</span>
          {[['kyuukyuu','至急！'],['kakunin','ご確認ください'],['orikaesu','折り返しご連絡ください']].map(([k,label])=>(
            <label key={k} style={{display:'flex',alignItems:'center',gap:4,fontSize:12,fontWeight:'bold',cursor:'pointer',whiteSpace:'nowrap'}}>
              <input type="checkbox" checked={checks[k]} onChange={e=>setChecks(c=>({...c,[k]:e.target.checked}))}
                     style={{width:14,height:14,accentColor:'#22c55e',cursor:'pointer'}}/>
              <span style={{color:checks[k]?'white':'#94a3b8'}}>{label}</span>
            </label>
          ))}
        </div>
        <div style={{marginLeft:'auto',display:'flex',gap:8}}>
          <button type="button" onClick={handlePreview}
                  style={{background:'#0f766e',border:'none',color:'white',borderRadius:8,padding:'6px 14px',fontWeight:'bold',fontSize:12,cursor:'pointer',display:'flex',alignItems:'center',gap:5}}>
            📋 プレビュー
          </button>
          <button type="button" onClick={()=>setShowFaxHist(true)}
                  style={{background:'#7c3aed',border:'none',color:'white',borderRadius:8,padding:'6px 14px',fontWeight:'bold',fontSize:12,cursor:'pointer',display:'flex',alignItems:'center',gap:5}}>
            📋 履歴
          </button>
        </div>
      </div>

      <style>{`
        @page { size: A4 portrait; margin: 0; }
        @media print {
          body, html { margin:0!important; padding:0!important; overflow:hidden!important; width:210mm!important; height:297mm!important; }
          body { display:flex!important; justify-content:center!important; align-items:flex-start!important; }
          body>* { margin:0!important; padding:0!important; }
          #print-content-general-fax {
            width:190mm!important; height:280mm!important; max-height:280mm!important;
            margin:8mm auto!important;
            box-shadow:none!important;
            page-break-after:avoid!important; break-after:avoid!important;
            page-break-inside:avoid!important; break-inside:avoid!important;
            overflow:hidden!important;
          }
        }
      `}</style>
      <div style={{flex:1,overflow:'auto',padding:'20px',display:'flex',alignItems:'flex-start',justifyContent:'center'}}>
        {/* A4 送付状プレビュー（件名・連絡事項は中で直接編集可能） */}
        <div id="print-content-general-fax"
             style={{width:'190mm',height:'280mm',maxHeight:'280mm',overflow:'hidden',background:'white',boxShadow:'0 4px 24px rgba(0,0,0,0.12)',padding:'12mm 14mm',boxSizing:'border-box',fontFamily:'serif',display:'flex',flexDirection:'column',margin:'0 auto'}}>

          {/* タイトル */}
          <div style={{textAlign:'center',fontSize:28,fontWeight:'bold',border:'3px solid black',padding:'10px 0',marginBottom:28,letterSpacing:6}}>送付状</div>

          {/* 上部2列 */}
          <div style={{display:'flex',gap:0,marginBottom:20}}>
            <div style={{flex:1,paddingRight:24}}>
              <div style={{display:'grid',gridTemplateColumns:'90px 1fr',gap:'8px 10px',marginBottom:16,fontSize:16}}>
                <span style={{fontWeight:'bold'}}>送付日：</span>
                <span>{today}</span>
                <span style={{fontWeight:'bold'}}>送付枚数：</span>
                <span>{pageCount} 枚（表紙含）</span>
                <span style={{fontWeight:'bold'}}>送付先：</span>
                <span></span>
              </div>
              <div style={{marginLeft:90,marginBottom:10,fontSize:17,borderBottom:'1px solid black',paddingBottom:5,display:'flex',justifyContent:'space-between',alignItems:'flex-end',gap:8}}>
                <input type="text" value={recipientOffice} onChange={e=>setRecipientOffice(e.target.value)}
                       placeholder="(送付先名)" className="fax-inline-input"
                       style={{flex:1,minWidth:0,fontSize:17,border:'none',outline:'none',background:'transparent',padding:'2px 4px',fontFamily:'inherit'}}/>
                <span style={{fontWeight:'bold',flexShrink:0,whiteSpace:'nowrap'}}>御中</span>
              </div>
              <div style={{marginLeft:90,marginBottom:10,fontSize:17,borderBottom:'1px solid black',paddingBottom:5,display:'flex',justifyContent:'space-between',alignItems:'flex-end',gap:8}}>
                <input type="text" value={recipientName} onChange={e=>setRecipientName(e.target.value)}
                       placeholder="(担当者名)" className="fax-inline-input"
                       style={{flex:1,minWidth:0,fontSize:17,border:'none',outline:'none',background:'transparent',padding:'2px 4px',fontFamily:'inherit'}}/>
                <span style={{fontWeight:'bold',flexShrink:0,whiteSpace:'nowrap'}}>様</span>
              </div>
              {patient?.cmFax && (
                <div style={{marginLeft:90,fontSize:14,color:'#475569',marginTop:6}}>
                  FAX：{patient.cmFax}
                </div>
              )}
            </div>
            <div style={{width:280,border:'2px solid black',padding:'12px 16px',fontSize:16,lineHeight:1.7}}>
              <AutoFitLine style={{fontWeight:'bold',fontSize:19,marginBottom:6,display:'block',width:'100%'}}>{facility.name || 'ひかりデイサービス扇橋店'}</AutoFitLine>
              <AutoFitLine style={{display:'block',width:'100%'}}>〒{facility.zip||'135-0011'}</AutoFitLine>
              <AutoFitLine style={{display:'block',width:'100%'}}>{facility.address||'東京都江東区扇橋1-4-9メイゾン白子'}</AutoFitLine>
              <AutoFitLine style={{display:'block',width:'100%'}}>TEL：{facility.phone||'03-6458-7415'}</AutoFitLine>
              <AutoFitLine style={{display:'block',width:'100%'}}>FAX：{facility.fax||'03-6458-7416'}</AutoFitLine>
              <div style={{display:'flex',alignItems:'center',gap:4,width:'100%'}}>
                <span style={{whiteSpace:'nowrap'}}>担当：　</span>
                <select value={selectedManager} onChange={e=>setSelectedManager(e.target.value)}
                  className="fax-inline-input"
                  style={{flex:1,fontSize:16,fontFamily:'inherit',border:'none',outline:'none',background:'transparent',padding:'0 2px',cursor:'pointer',appearance:'none',WebkitAppearance:'none',MozAppearance:'none',color:'inherit'}}>
                  {staffList.length === 0 && <option value="">（従業員未登録）</option>}
                  {staffList.map((s, i) => (
                    <option key={s.id || i} value={s.name}>{s.name}{s.role ? `（${s.role}）` : ''}</option>
                  ))}
                </select>
              </div>
            </div>
          </div>

          {/* 件名（送付状内で直接編集可能） */}
          <div style={{display:'flex',alignItems:'center',gap:16,marginBottom:20,borderBottom:'3px double black',paddingBottom:12}}>
            <span style={{fontSize:16,fontWeight:'bold',whiteSpace:'nowrap'}}>件名：</span>
            <input type="text" value={subject} onChange={e=>setSubject(e.target.value)}
                   placeholder="例: 介護計画書のご確認"
                   className="fax-inline-input"
                   style={{flex:1,fontSize:20,fontWeight:'bold',letterSpacing:2,border:'none',outline:'none',background:'transparent',padding:'2px 4px',fontFamily:'inherit'}}/>
          </div>

          {/* チェックボックス（表示用） */}
          <div style={{display:'flex',gap:28,marginBottom:12,fontSize:13,fontWeight:'bold',alignItems:'center'}}>
            {[['kyuukyuu','至急！'],['kakunin','ご確認ください'],['orikaesu','折り返しご連絡ください']].map(([k,label])=>(
              <span key={k} style={{display:'flex',alignItems:'center',gap:6}}>
                <span style={{display:'inline-flex',alignItems:'center',justifyContent:'center',width:16,height:16,border:`2px solid ${checks[k]?'#1e293b':'#94a3b8'}`,borderRadius:3,background:checks[k]?'#1e293b':'white',color:'white',fontSize:11,fontWeight:'bold',flexShrink:0}}>{checks[k]?'✓':''}</span>
                <span style={{color:checks[k]?'#1e293b':'#94a3b8'}}>{label}</span>
              </span>
            ))}
          </div>

          <div style={{fontSize:11,color:'#334155',marginBottom:16}}>・送付されていないページがありましたら、至急ご連絡ください。</div>

          {/* 本文枠 — 利用者名 + 連絡事項（送付状内で直接編集可能） */}
          {/* 利用者未選択時は利用者名行を省略し、連絡事項エリアを拡張 */}
          <div style={{border:'2px solid black',padding:'24px 28px',lineHeight:2.2,fontSize:13,flex:1,display:'flex',flexDirection:'column',minHeight:500}}>
            {patient && (
              <div style={{fontSize:19,fontWeight:'bold',marginBottom:20,borderBottom:'1px solid #e2e8f0',paddingBottom:14,display:'flex',alignItems:'center',gap:8}}>
                <span style={{color:'#475569',fontWeight:'bold',whiteSpace:'nowrap'}}>利用者名：</span>
                <span style={{borderBottom:'2px solid #1e293b',paddingBottom:2,letterSpacing:2}}>{maskedName}</span>
                <span>様</span>
              </div>
            )}
            <textarea value={memo} onChange={e=>setMemo(e.target.value)}
                      placeholder="ここに連絡事項を直接入力してください"
                      className="fax-inline-input"
                      style={{flex:1,fontSize:16,lineHeight:1.9,padding:'4px 0',border:'none',outline:'none',background:'transparent',resize:'none',fontFamily:'inherit',width:'100%'}}/>
            <div style={{fontSize:13,marginTop:8}}>今後ともよろしくお願いいたします。</div>
          </div>
        </div>
      </div>
      {showFaxHist && <FaxHistoryListModal history={genHistory} typeLabel="各種連絡" onDelete={deleteGenHist} onClose={()=>setShowFaxHist(false)}/>}
    </div>
  );
}


// === プレースホルダー画面 ===
function PlaceholderView({ title, icon, description, color = "text-blue-500" }) {
  return (
    <div className="h-full flex flex-col items-center justify-center bg-slate-50">
       <div className={`${color} mb-4 animate-bounce`}>{icon}</div>
       <h2 className="text-2xl font-bold text-slate-700 mb-2">{title}（開発中）</h2>
       <p className="text-slate-500 text-center max-w-md">{description}</p>
    </div>
  );
}
